import numpy as np
from scipy.optimize import minimize, NonlinearConstraint

def construct_packing():
    """Jointly optimize all 78 variables (26 circles × 3: x, y, r) using trust-constr."""
    n = 26

    # Initial hexagonal pattern
    pts = []
    s, h = 0.2, 0.2 * np.sqrt(3) / 2
    for i in range(5): pts.append([0.1 + i*s, 0.1])
    for i in range(4): pts.append([0.2 + i*s, 0.1 + h])
    for i in range(5): pts.append([0.1 + i*s, 0.1 + 2*h])
    for i in range(4): pts.append([0.2 + i*s, 0.1 + 3*h])
    for i in range(5): pts.append([0.1 + i*s, 0.1 + 4*h])
    for x in [0.1, 0.5, 0.9]: pts.append([x, 0.95])
    pts = np.array(pts)

    def compute_radii(centers):
        radii = np.array([min(c[0], c[1], 1-c[0], 1-c[1]) for c in centers])
        for _ in range(100):
            for i in range(n):
                for j in range(i+1, n):
                    d = np.linalg.norm(centers[i] - centers[j])
                    if radii[i] + radii[j] > d and d > 1e-10:
                        total = radii[i] + radii[j]
                        radii[i] = d * radii[i] / total
                        radii[j] = d * radii[j] / total
        return radii

    r0 = compute_radii(pts)
    x0 = np.zeros(3*n)
    for i in range(n):
        x0[3*i:3*i+3] = [pts[i,0], pts[i,1], r0[i]]

    def obj(x):
        return -np.sum(x[2::3])

    def cons(x):
        c = []
        for i in range(n):
            xi, yi, ri = x[3*i], x[3*i+1], x[3*i+2]
            c.extend([xi-ri, 1-xi-ri, yi-ri, 1-yi-ri])
        for i in range(n):
            for j in range(i+1, n):
                d2 = (x[3*i]-x[3*j])**2 + (x[3*i+1]-x[3*j+1])**2
                c.append(d2 - (x[3*i+2]+x[3*j+2])**2)
        return np.array(c)

    bounds = [(0,1), (0,1), (0,0.5)] * n
    nlc = NonlinearConstraint(cons, 0.0, np.inf)

    res = minimize(obj, x0, method='trust-constr', constraints=[nlc],
                   bounds=bounds, options={'maxiter': 1000})

    centers = np.array([[res.x[3*i], res.x[3*i+1]] for i in range(n)])
    radii = compute_radii(centers)

    return centers, radii, np.sum(radii)

